var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"PIRATE_NPC_SAILOR_A","text":{"KOREA":"젠장! 한탕 하려고 구조신호를 쫓아왔는데 왜 전투함들이 잔뜩 있는 거야!","JPN":"くそ！　一稼ぎできると思って救助信号を追ってきたのに、なんで戦闘艦ばかりなんだよ！","ENG":"Drat! We've followed the rescue signals. Why are there so many warships here?","TWN":"該死！收到求救訊號趕過來想大幹一場，誰能告訴我為什麼會有這麼多戰鬥艦？？？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIRATE_NPC_SAILOR_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PIRATE_NPC_SAILOR_A","text":{"KOREA":"이러다 전부 철창행이야! 어서 후퇴해!","JPN":"このままじゃ全員刑務所送りだ！　はやく撤退しろ！","ENG":"I don't want to go to prison! Come on, let's leave!","TWN":"這樣下去會全軍覆沒的！立刻撤退！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIRATE_NPC_SAILOR_A","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_EXPLOSION_FIRE_BIG"},{"id":"L6_1","type":"dialog","speaker":"PIRATE_NPC_SAILOR_B","text":{"KOREA":"망할! 다이브가 안 돼! 누가 벌써 우리가 넘어 왔던 차원 항로를 막아놨어!","JPN":"ちくしょう！　ダイブできない！　誰か俺らが使った次元航路を封じたんだ！","ENG":"Dammit! We can't Dive! Somebody blocked the dimensional route we used!","TWN":"可惡！沒辦法躍入！不知道是誰關閉了我們穿越的次元航道！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIRATE_NPC_SAILOR_B","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L7_1","type":"dialog","speaker":"PIRATE_NPC_SAILOR_A","text":{"KOREA":"그럼 쏴! 일단 쏘라고!","JPN":"なら、撃て！　とにかく撃ちまくれ！","ENG":"Then, shoot! Start shooting!","TWN":"那就發射！全力發射！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIRATE_NPC_SAILOR_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"저놈들. 성난 황소한테 쫓기는 생쥐들 같군.","JPN":"あいつら、興奮した雄牛に追われるネズミみたいだな。","ENG":"Those fools, they're like rats being chased by an angry bull.","TWN":"那些傢伙還真是窮追不捨。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"당연하지.","JPN":"当然さ。","ENG":"Of course.","TWN":"那還用說！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"그래도 용병들인데 조난선이나 쫓는 삼류 해적들한테 당할 리 없으니까.","JPN":"名ばかりでも一応傭兵だ。遭難船ばかりを狙う三流海賊にやられるはずがない。","ENG":"Third-rate pirates like them, who chase stranded ships, could never beat professional mercenaries.","TWN":"再怎麼說他們也是傭兵，那些整天追著遇難船隻跑的三流海盜，怎麼可能擋得住他們！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"뭐, 저 해적들은 우리가 서브스톰으로 다이브하기 전까지 시간만 벌어 주면 돼.","JPN":"まあ、あの海賊は俺らがサブストームにダイブするまで時間稼ぎだけしてくれりゃあいい。","ENG":"Well, let's hope they'll last until we can Dive back to Substorm.","TWN":"反正那些海盜只需要在我們躍入次級風暴前，幫我們拖延時間就好。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"글쎄. 생쥐들을 무시하고 우리한테 따라붙은 놈들이 있는 모양이군. ","JPN":"さて。ネズミどもを無視して俺たちに追いついたやつらがいるようだ。","ENG":"Well, some mercenaries are just following us instead of the rats. ","TWN":"不過，好像有人閃過那些海盜緊追著我們不放？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"상황이 네 생각대로 안 굴러가는 것 같은데.","JPN":"状況がお前の思いどおりに行かないようだが。","ENG":"Things are not going the way you want.","TWN":"現在情況跟你原本的預期似乎有落差呢？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"쳇……!","JPN":"チッ……！","ENG":"Bah!","TWN":"嗟……！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"빌어먹을, 저것들은 어떻게 총알받이로도 못 써먹는 거지?","JPN":"くそ、あいつらは弾除けとしても使えねえのかよ！","ENG":"Those fools aren't even useful as cannon fodder.","TWN":"沒用的東西！那些傢伙連當擋箭牌都當不好！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"어이! 우리 공격받고 있는데?","JPN":"おい！　俺たち攻撃されてるぞ？","ENG":"Hey, we're under attack!","TWN":"喂！我們被攻擊了啦！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"이 상태로는 서브스톰까지 한 번에 다이브하긴 어렵겠어!","JPN":"この状態じゃサブストームまでダイブするのは難しい！","ENG":"There's no way we can Dive all the way back to Substorm!","TWN":"這種狀態下根本無法一次就躍入次級風暴吧！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"흥, 한 번에 갈 수 없으면 단계적으로 가면 돼.","JPN":"ふん、いっきに行けないなら段階的に向かえばいい。","ENG":"Hmpf, we don't have to get there all at once; we can go in stages.","TWN":"哼！無法一次躍入，那你不會分階段嗎！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"이터니움 드라이브에 과부하 걸어!","JPN":"エタニウムドライブに過負荷をかけろ！","ENG":"Overclock the Eternium Drive!","TWN":"永恆之金引擎負荷過大！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"급강하 개시! 추격하는 놈들이 나가떨어질 때까지 차원계면을 연속으로 돌파한다!","JPN":"急降下開始！　追撃するやつらが諦めるまで次元界面を連続で突破する！","ENG":"Take a nosedive! We'll go through all the way of dimension surfaces until the pursuers fall out!","TWN":"開始緊急降落！在那些傢伙收手前，給我持續突破次元邊界！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"허수공간으로 튕겨 나가기 싫으면 계기판에서 눈 돌리지 마!","JPN":"虚数空間に弾き飛ばされたくなきゃ、計器盤から目を離すな！","ENG":"If you don't want to end up in an imaginary space, keep your eyes on the instrument panel!","TWN":"要是不想被彈到量子空間裡，眼睛就給我死盯著儀表板！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"오케이, 세뇨라!","JPN":"OK、セニョーラ！","ENG":"Si, señorita!","TWN":"Ok！Senora！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SCAVANGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_30"}]`);export{e as default};